/**
 * Ref of the PieChart
 * @public
 */
export interface PieChartRef {
    /** Chart div element */
    element: HTMLDivElement | null;
    /** Returns the current serialized config of the PieChart.*/
    getConfig: () => string;
    /** Downloads pie chart raw data .*/
    downloadData: () => void;
}
/**
 * Ref of the DonutChartRef
 * @public
 */
export type DonutChartRef = PieChartRef;
